{
  "module": "01-layout.md",
  "group": "01 — Layout & Container Components",
  "apiCount": 11,
  "apis": [
    {
      "name": "Blank",
      "purpose": "空白填充组件，在父容器(Row/Column/Flex)主轴方向自动填充空余空间",
      "anchor": "blank",
      "status": "found"
    },
    {
      "name": "Column",
      "purpose": "沿垂直方向布局的容器，可设置子组件间距和对齐方式",
      "anchor": "column",
      "status": "found"
    },
    {
      "name": "Divider",
      "purpose": "分割线组件，分割不同内容块/内容元素，支持水平和垂直方向",
      "anchor": "divider",
      "status": "found"
    },
    {
      "name": "Flex",
      "purpose": "弹性方式布局子组件的容器，支持direction/wrap/justifyContent/alignItems/space参数",
      "anchor": "flex",
      "status": "found"
    },
    {
      "name": "ForEach",
      "purpose": "基于数组类型数据进行循环渲染的声明式语句，需配合容器组件使用",
      "anchor": "foreach",
      "status": "found"
    },
    {
      "name": "Grid",
      "purpose": "网格容器，由行列分割的单元格组成，支持固定行列和可滚动模式",
      "anchor": "grid",
      "status": "found"
    },
    {
      "name": "List",
      "purpose": "列表容器，包含一系列相同宽度的列表项，支持懒加载和预加载",
      "anchor": "list",
      "status": "found"
    },
    {
      "name": "Row",
      "purpose": "沿水平方向布局的容器，可设置子组件间距和对齐方式",
      "anchor": "row",
      "status": "found"
    },
    {
      "name": "Scroll",
      "purpose": "可滚动的容器组件，子组件尺寸超出父组件时内容可滚动",
      "anchor": "scroll",
      "status": "found"
    },
    {
      "name": "Stack",
      "purpose": "堆叠容器，子组件按顺序依次入栈，后一个覆盖前一个",
      "anchor": "stack",
      "status": "found"
    },
    {
      "name": "Swiper",
      "purpose": "滑块视图容器，提供子组件滑动轮播显示能力，支持自动播放和导航点",
      "anchor": "swiper",
      "status": "found"
    }
  ],
  "notableFindings": [
    "Flex 渲染时存在二次布局过程，性能要求严格的场景建议使用 Column/Row 代替",
    "List 的懒加载推荐结合 LazyForEach 或带 virtualScroll 的 Repeat 使用，与 ForEach 结合时不会真正销毁划出屏幕的节点",
    "Grid 有三种布局模式：仅设 rowsTemplate/columnsTemplate(可滚动)、两者同时设置(固定行列)、均不设置(自动排布)",
    "Blank 仅在父组件为 Row/Column/Flex 时生效",
    "控制器类(Scroller/SwiperController)及工具类(LengthMetrics/curves)需从 @kit.ArkUI 导入，组件本身无需 import"
  ],
  "missingApis": []
}

{
  "module": "02-navigation.md",
  "group": "02 — Navigation & Tabs",
  "apiCount": 7,
  "apis": [
    {
      "name": "Navigation",
      "purpose": "路由导航根视图容器，作为Page页面的根容器，支持NavPathStack页面路由",
      "anchor": "navigation",
      "status": "found"
    },
    {
      "name": "Tabs",
      "purpose": "页签内容视图切换容器组件，通过页签切换对应TabContent内容",
      "anchor": "tabs",
      "status": "found"
    },
    {
      "name": "TabContent",
      "purpose": "Tabs子组件，对应一个切换页签的内容视图",
      "anchor": "tabcontent",
      "status": "found"
    },
    {
      "name": "Navigation + NavPathStack (recommended routing)",
      "purpose": "现代页面路由方案，使用NavPathStack管理路由栈和NavDestination页面",
      "anchor": "navpathstack10",
      "status": "found"
    },
    {
      "name": "NavRouter",
      "purpose": "导航点击响应组件（已废弃，API 13起不再维护），推荐使用NavPathStack替代",
      "anchor": "navrouterdeprecated",
      "status": "found"
    },
    {
      "name": "NavDestination",
      "purpose": "Navigation子页面的根容器，配合Navigation实现页面路由",
      "anchor": "navdestination",
      "status": "found"
    },
    {
      "name": "@ohos.router",
      "purpose": "页面路由模块（已废弃，API 18起不推荐），提供url/命名路由跳转、替换、返回功能",
      "anchor": "ohosrouter-页面路由不推荐",
      "status": "found"
    }
  ],
  "notableFindings": [
    "Navigation + NavPathStack (API 10+) 是推荐的路由方案，替代已废弃的 NavRouter (API 13+) 和 @ohos.router (API 18+)",
    "NavRouter 从 API 13 起不再维护，存放在已停止维护的组件目录中",
    "@ohos.router 的 pushUrl/replaceUrl/pushNamedRoute 从 API 18 起废弃，替代方案为 UIContext.getRouter() 获取 Router 实例或迁移至 Navigation 组件",
    "Tabs 仅支持 TabContent 作为直接子组件，不推荐自定义组件作为直接子组件",
    "TabContent.tabBar 支持 SubTabBarStyle（顶部文字+下划线）和 BottomTabBarStyle（底部图标+文字）两种内置样式",
    "NavDestination 必须配合 Navigation 使用，单独使用仅作为普通容器不具备路由能力"
  ],
  "missingApis": []
}

{
  "module": "03-controls.md",
  "group": "03 — Controls & Input Components",
  "apiCount": 9,
  "apis": [
    {
      "name": "Button",
      "purpose": "创建按钮组件，支持 Normal/Capsule/Circle/ROUNDED_RECTANGLE 四种样式与强调度模式",
      "anchor": "button",
      "status": "found"
    },
    {
      "name": "Toggle",
      "purpose": "多样式切换组件，支持 Checkbox/Switch/Button 三种开关类型",
      "anchor": "toggle",
      "status": "found"
    },
    {
      "name": "Checkbox",
      "purpose": "多选复选框组件，支持分组、自定义选中颜色和形状（圆形/圆角方形）",
      "anchor": "checkbox",
      "status": "found"
    },
    {
      "name": "Radio",
      "purpose": "单选框组件，通过 group 名分组成员互斥，支持 TICK/DOT/CUSTOM 指示器",
      "anchor": "radio",
      "status": "found"
    },
    {
      "name": "DatePicker",
      "purpose": "日期滑动选择器，支持 DATE/YEAR_AND_MONTH/MONTH_AND_DAY 三种模式及农历",
      "anchor": "datepicker",
      "status": "found"
    },
    {
      "name": "Select",
      "purpose": "下拉选择菜单，通过 Array<SelectOption> 配置选项，支持图标和自定义菜单样式",
      "anchor": "select",
      "status": "found"
    },
    {
      "name": "TextInput",
      "purpose": "单行文本输入，支持 Normal/Password/Email/Phone/Number 等输入类型和输入过滤",
      "anchor": "textinput",
      "status": "found"
    },
    {
      "name": "TextArea",
      "purpose": "多行文本输入，支持自动换行、字符计数、自适应字号和富文本样式",
      "anchor": "textarea",
      "status": "found"
    },
    {
      "name": "Search",
      "purpose": "搜索输入组件，内置搜索图标/按钮，支持 onSubmit 搜索事件和扩展输入类型",
      "anchor": "search",
      "status": "found"
    }
  ],
  "notableFindings": [
    "Button 默认样式在 API 18 版本后从 Capsule 变更为 ROUNDED_RECTANGLE",
    "Search 组件的 enterKeyType 默认值为 Search，与 TextInput 不同",
    "Select 使用 Array<SelectOption> 配置而非子组件构建，不支持子组件内容",
    "TextInput 与 TextArea 共享相近的属性集，TextArea 额外支持 maxLines 和自适应字号",
    "所有组件均为 ArkUI 内置组件，无需 import 语句，控制器类需从 @kit.ArkUI 导入"
  ],
  "missingApis": []
}

{
  "module": "04-dialogs-media.md",
  "group": "04 — Dialogs, Feedback & Media",
  "apiCount": 8,
  "apis": [
    {
      "name": "AlertDialog",
      "purpose": "显示警告弹窗，可配置标题/消息/按钮/遮罩/生命周期回调",
      "anchor": "alertdialog",
      "status": "found"
    },
    {
      "name": "CustomDialog",
      "purpose": "通过CustomDialogController显示完全自定义样式的弹窗",
      "anchor": "customdialog",
      "status": "found"
    },
    {
      "name": "BottomSheet (bindSheet)",
      "purpose": "通过bindSheet通用属性为组件绑定半模态页面，支持多高度挡位和多种样式",
      "anchor": "bindsheet",
      "status": "found"
    },
    {
      "name": "Toast (promptAction.showToast)",
      "purpose": "显示即时反馈Toast提示，支持自定义消息/时长/对齐/颜色/阴影",
      "anchor": "toast-promptactionshowtoast",
      "status": "found"
    },
    {
      "name": "PhotoViewPicker",
      "purpose": "拉起系统图库选择器供用户选择图片/视频，返回永久授权URI",
      "anchor": "photoviewpicker",
      "status": "found"
    },
    {
      "name": "Image",
      "purpose": "图片组件，加载并显示本地/网络/像素图/Bitmap等多种数据源的图片",
      "anchor": "image",
      "status": "found"
    },
    {
      "name": "ImageAnimator",
      "purpose": "帧动画组件，配置图片帧列表实现逐帧播放，支持播放状态/时长/循环控制",
      "anchor": "imageanimator",
      "status": "found"
    },
    {
      "name": "Menu",
      "purpose": "垂直列表菜单容器，需配合bindMenu或bindContextMenu使用，支持多级子菜单",
      "anchor": "menu",
      "status": "found"
    }
  ],
  "notableFindings": [
    "AlertDialog.show() 已废弃 (API 18)，应使用 UIContext.showAlertDialog() 替代",
    "promptAction.showToast() 已废弃 (API 18)，应使用 promptAction.openToast() 或 UIContext.getPromptAction().openToast()",
    "bindSheet 的 isShow 参数推荐使用 $$ 双向绑定以实现拖拽关闭状态同步",
    "Menu 组件不能单独使用，必须配合 bindMenu 或 bindContextMenu 属性方法",
    "PhotoViewPicker 返回的 photoUris 具有永久授权，可通过 photoAccessHelper.getAssets 访问",
    "Image 加载网络图片需声明 ohos.permission.INTERNET 权限",
    "ImageAnimator 的 images 属性不支持运行时动态更新，需一次性传入完整帧数组",
    "BottomSheet 在 HarmonyOS 中没有独立组件，其概念完全由 bindSheet 半模态转场实现"
  ],
  "missingApis": []
}

{
  "module": "05-state.md",
  "group": "05 — State Management & Lifecycle",
  "apiCount": 17,
  "apis": [
    {
      "name": "@State",
      "purpose": "组件内状态变量装饰器，标记属性为响应式数据以驱动UI刷新",
      "anchor": "@state",
      "status": "missing"
    },
    {
      "name": "@Prop",
      "purpose": "父组件到子组件的单向数据同步装饰器",
      "anchor": "@prop",
      "status": "missing"
    },
    {
      "name": "@Link",
      "purpose": "父子组件间双向数据同步装饰器",
      "anchor": "@link",
      "status": "missing"
    },
    {
      "name": "@Provide/@Consume",
      "purpose": "跨组件层级数据提供与消费装饰器",
      "anchor": "@provide-@consume",
      "status": "missing"
    },
    {
      "name": "@ObjectLink",
      "purpose": "装饰@Observed类对象引用的子组件装饰器",
      "anchor": "@objectlink",
      "status": "missing"
    },
    {
      "name": "@Watch",
      "purpose": "状态变量变化监听装饰器（V1），注册回调监听指定状态变量变化",
      "anchor": "watch",
      "status": "found"
    },
    {
      "name": "@Builder",
      "purpose": "自定义构建函数装饰器，封装可复用的UI描述",
      "anchor": "@builder",
      "status": "missing"
    },
    {
      "name": "@Styles",
      "purpose": "定义组件通用样式函数的装饰器",
      "anchor": "@styles",
      "status": "missing"
    },
    {
      "name": "@Extend",
      "purpose": "扩展原生组件样式的装饰器",
      "anchor": "@extend",
      "status": "missing"
    },
    {
      "name": "@StorageLink",
      "purpose": "AppStorage双向同步装饰器，将组件属性与AppStorage键值双向绑定",
      "anchor": "@storagelink",
      "status": "missing"
    },
    {
      "name": "@StorageProp",
      "purpose": "AppStorage单向同步装饰器，从AppStorage读取数据到组件属性",
      "anchor": "@storageprop",
      "status": "missing"
    },
    {
      "name": "@LocalStorageLink",
      "purpose": "LocalStorage双向同步装饰器",
      "anchor": "@localstoragelink",
      "status": "missing"
    },
    {
      "name": "aboutToAppear",
      "purpose": "自定义组件build()执行前的生命周期回调，用于初始化逻辑",
      "anchor": "abouttoappear",
      "status": "found"
    },
    {
      "name": "aboutToDisappear",
      "purpose": "自定义组件析构销毁时的生命周期回调",
      "anchor": "abouttodisappear",
      "status": "found"
    },
    {
      "name": "build()",
      "purpose": "自定义组件必须定义的声明式UI描述函数",
      "anchor": "build",
      "status": "found"
    },
    {
      "name": "LazyForEach",
      "purpose": "基于IDataSource数据源的按需迭代循环渲染组件，支持懒加载",
      "anchor": "lazyforeach",
      "status": "found"
    },
    {
      "name": "ForEach (状态管理中数据循环渲染)",
      "purpose": "基于数组数据的循环渲染组件，与容器组件配合使用",
      "anchor": "foreach",
      "status": "found"
    }
  ],
  "notableFindings": [
    "HarmonyOS has two state management systems: V1 (@State/@Prop/@Link/@Provide/@Consume/@ObjectLink/@Watch, API 7+) and V2 (@ObservedV2/@Trace/@Monitor, API 12+); V1 remains mainstream for most apps",
    "@State, @Prop, @Link, @Provide/@Consume, @ObjectLink, @Builder, @Styles, @Extend are compile-time built-in decorators with no standalone API reference files in the local docs repo — they are documented exclusively in HarmonyOS developer guides",
    "@StorageLink, @StorageProp, @LocalStorageLink are referenced in the AppStorage/LocalStorage API reference doc (01_应用级变量的状态管理.md) but have no separate documentation pages",
    "ProvideOptions (for @Provide allowOverride) is the only V1 decorator with a dedicated API reference entry, in 02_状态管理V1装饰器参数.md",
    "Recommended lifecycle (V2, API 23+): @ComponentInit, @ComponentAppear, @ComponentBuilt, @ComponentDisappear — separate from classic aboutToAppear/aboutToDisappear lifecycle",
    "AppStorageV2/PersistenceV2 are available via `import { AppStorageV2, PersistenceV2, UIUtils } from '@kit.ArkUI'` (API 12+) as the V2 replacement for AppStorage/PersistentStorage"
  ],
  "missingApis": [
    "@State",
    "@Prop",
    "@Link",
    "@Provide/@Consume",
    "@ObjectLink",
    "@Builder",
    "@Styles",
    "@Extend",
    "@StorageLink",
    "@StorageProp",
    "@LocalStorageLink"
  ]
}

{
  "module": "06-persistence.md",
  "group": "Data Persistence, Permissions & Resources",
  "apiCount": 9,
  "apis": [
    {
      "name": "ohos.data.preferences (Preferences)",
