      "anchor": "ohosabilityaccessctrl-atmanager",
      "status": "found"
    },
    {
      "name": "$r (系统资源引用)",
      "purpose": "ArkUI 内置资源引用语法, 通过 $r('app.type.name') 引用应用或系统资源文件",
